def parse_config(path):
    data = {}
    with open(path) as f:
        for line in f:
            line = line.strip()
            if not line or line.startswith('#'):
                continue
            key, _, value = line.partition('=')
            data[key.strip()] = value.strip()
    return data


def daily_report(path):
    cfg = parse_config(path)
    return f"daily: {cfg.get('title', 'untitled')}"

