def categorize(user):
    if user is not None:
        if user.get('active'):
            if user.get('admin'):
                if user.get('verified'):
                    return 'admin'
                else:
                    return 'pending-admin'
            else:
                return 'member'
        else:
            return 'inactive'
    else:
        return 'unknown'
